export const code = async (inputs) => {
  const regions = (typeof inputs.regions_array === 'string' 
    ? JSON.parse(inputs.regions_array) 
    : inputs.regions_array) as any[];

  const subscriptions = (typeof inputs.subscriptions_array === 'string' 
    ? JSON.parse(inputs.subscriptions_array) 
    : inputs.subscriptions_array) as any[];

  return { regions, subscriptions };
};

export const code = async (inputs) => {
  const payload = inputs?.storagePercent;
  if (!payload || !Array.isArray(payload.timeseries)) {
    return 0;
  }

  let maxVal = 0;

  for (const series of payload.timeseries) {
    if (!series || !Array.isArray(series.data)) continue;

    for (const point of series.data) {
      const value = point?.maximum;
      if (typeof value === "number" && value > maxVal) {
        maxVal = value;
      }
    }
  }

  return maxVal;
};

export const code = async (inputs) => {
  const elasticPool = inputs?.elasticPool ?? {};
  const pricingList = Array.isArray(inputs?.pricingList) ? inputs.pricingList : [];

  const tierRaw =
    elasticPool?.sku?.tier ??
    elasticPool?.edition ??
    elasticPool?.sku?.name ??
    "";

  const tier = String(tierRaw).toLowerCase();
  const zoneRedundant = elasticPool?.zoneRedundant === true;

  const normalize = (v) => String(v ?? "").toLowerCase();

  const candidates = pricingList.filter(
    (p) =>
      normalize(p.unitOfMeasure) === "1 gb/month" &&
      Number(p.unitPrice ?? 0) > 0 &&
      !normalize(p.productName).includes("backup") &&
      !normalize(p.meterName).includes("backup")
  );

  const find = (fn) => candidates.find(fn);

  let selected;

  if (tier.includes("businesscritical") || tier.includes("business critical")) {
    selected = find((p) => normalize(p.meterName).includes("business critical"));
  } else if (zoneRedundant) {
    selected = find((p) => normalize(p.meterName).includes("zone redundancy"));
  } else if (tier.includes("generalpurpose") || tier.includes("general purpose")) {
    selected = find(
      (p) =>
        normalize(p.meterName).includes("general purpose data stored") &&
        !normalize(p.meterName).includes("zone redundancy")
    );
  }

  if (!selected) {
    selected =
      find((p) => normalize(p.meterName).includes("data stored")) ||
      candidates.sort((a, b) => a.unitPrice - b.unitPrice)[0] ||
      pricingList[0];
  }

  return {
    currencyCode: selected?.currencyCode,
    meterName: selected?.meterName,
    productName: selected?.productName,
    skuName: selected?.skuName,
    unitOfMeasure: selected?.unitOfMeasure,
    unitPrice: selected?.unitPrice,
  };
};
